    private fun PsiElement.getPrevLeafIgnoringCommentAndWhitespaceExceptBlankLines(): PsiElement? {
        var prevLeaf: PsiElement? = this.prevLeaf()
        val iterator = prevLeafs.iterator()
        while (iterator.hasNext()) {
            val psiElement = iterator.next()
            if (psiElement is PsiComment || (psiElement is PsiWhiteSpace && psiElement.text?.count { it == '\n' } == 1)) {
                prevLeaf = psiElement
            } else {
                break
            }
        }
        return prevLeaf
    }

    /**
     * Checks if there are consecutive comments (multiple KDoc/block/EOL comments separated only by single-newline whitespace)
     * before this declaration. This is used to avoid adding a blank line when there are consecutive comments, as doing so
     * would create consecutive blank lines which violates the no-consecutive-blank-lines rule.
     */
    private fun PsiElement.hasConsecutiveCommentsBefore(): Boolean {
        var commentCount = 0
        var current = this.prevLeaf()

        while (current != null) {
            val elementType = current.node.elementType
            when {
                // Count each comment start (KDOC is the parent node, we want to count KDOC elements as one comment)
                elementType == KDOC || elementType == EOL_COMMENT || elementType == BLOCK_COMMENT -> {
                    commentCount++
                    if (commentCount >= 2) {
                        return true
                    }
                    // Skip to before this comment
                    current = current.node.treePrev?.psi
                }
                current is PsiWhiteSpace && current.text?.count { it == '\n' } == 1 -> {
                    // Single newline is okay between comments
                    current = current.prevLeaf()
                }
                else -> {
                    // Stop at blank lines or other elements
                    break
                }
            }
        }
        return false
    }

