    private fun PsiElement?.isWhitespaceBetweenComments(): Boolean {
        if (this == null || this !is PsiWhiteSpace || this.text?.count { it == '\n' } != 1) {
            return false
        }

        // Find the previous and next non-whitespace, non-comment-internal elements
        // by traversing through leaves
        var prevElement = this.prevLeaf()
        while (prevElement != null && prevElement.node.elementType in listOf(KDOC_END)) {
            prevElement = prevElement.prevLeaf()
        }

        var nextElement = this.node.treeNext?.psi
        while (nextElement != null && nextElement.node.elementType in listOf(KDOC_START)) {
            nextElement = nextElement.node.treeNext?.psi
        }

        // Check if we have comments on both sides (using parent KDOC nodes or comment nodes)
        val prevIsCommentStart = prevElement != null && 
            (prevElement.node.elementType == KDOC_START || 
             prevElement.node.elementType == KDOC ||
             prevElement.node.elementType == EOL_COMMENT || 
             prevElement.node.elementType == BLOCK_COMMENT)
        val nextIsKDoc = nextElement != null && nextElement.node.elementType == KDOC

        return prevIsCommentStart && nextIsKDoc
