     * Checks if there are consecutive comments (KDoc/block/EOL comments separated only by single-newline whitespace)
     * before this declaration.
     */
    private fun PsiElement.hasConsecutiveCommentsBefore(): Boolean {
        var commentCount = 0
        var seenKDocNodes = mutableSetOf<ASTNode>()
        var current = this.prevLeaf()

        while (current != null) {
            // Skip if we've already counted this KDOC parent node
            val kdocParent = current.node.treeParent?.takeIf { it.elementType == KDOC }
            if (kdocParent != null) {
                if (kdocParent !in seenKDocNodes) {
                    seenKDocNodes.add(kdocParent)
                    commentCount++
                    if (commentCount >= 2) {
                        return true
                    }
                }
                current = current.prevLeaf()
                continue
            }

            val elementType = current.node.elementType
            when {
                elementType == EOL_COMMENT || elementType == BLOCK_COMMENT -> {
                    commentCount++
                    if (commentCount >= 2) {
                        return true
                    }
                    current = current.prevLeaf()
                }
                current is PsiWhiteSpace && current.text?.count { it == '\n' } == 1 -> {
