    private fun PsiElement.getPrevLeafIgnoringCommentAndWhitespaceExceptBlankLines(): PsiElement? {
        var prevLeaf: PsiElement? = this.prevLeaf()
        val iterator = prevLeafs.iterator()
        while (iterator.hasNext()) {
            val psiElement = iterator.next()
            if (psiElement is PsiComment || (psiElement is PsiWhiteSpace && psiElement.text?.count { it == '\n' } == 1)) {
                prevLeaf = psiElement
            } else {
                break
            }
        }
        return prevLeaf
    }

    /**
     * Checks if there are consecutive comments (i.e., multiple comments separated only by single-newline whitespace)
     * before this element. This is used to avoid adding a blank line when there are consecutive comments, as doing so
     * would create consecutive blank lines which violates the no-consecutive-blank-lines rule.
     */
    private fun PsiElement.hasConsecutiveComments(): Boolean {
        var commentCount = 0
        val iterator = prevLeafs.iterator()
        while (iterator.hasNext()) {
            val psiElement = iterator.next()
            if (psiElement is PsiComment) {
                commentCount++
                if (commentCount >= 2) {
                    return true
                }
            } else if (psiElement is PsiWhiteSpace && psiElement.text?.count { it == '\n' } == 1) {
                // Continue checking - single newline whitespace is okay between comments
                continue
            } else {
                // Stop at any other element (blank lines, code, etc.)
                break
            }
        }
        return false
    }

    private fun ASTNode.hasAnnotationsAsChildren(): Boolean = children().find { it.psi is KtAnnotationEntry } != null"}

{"file_path": "/project/ktlint-ruleset-standard/src/test/kotlin/com/pinterest/ktlint/ruleset/standard/rules/SpacingBetweenDeclarationsWithAnnotationsRuleConsecutiveCommentsTest.kt", "content": "package com.pinterest.ktlint.ruleset.standard.rules

import com.pinterest.ktlint.test.KtLintAssertThat.Companion.assertThatRule
import org.junit.jupiter.api.Test

/**
 * Tests for the fix of consecutive KDoc comments issue where the spacing-between-declarations-with-annotations
 * rule was incorrectly adding a blank line, which then triggered the no-consecutive-blank-lines rule.
 *
 * See: https://github.com/pinterest/ktlint/issues/...
 */
class SpacingBetweenDeclarationsWithAnnotationsRuleConsecutiveCommentsTest {
    private val spacingBetweenDeclarationsWithAnnotationsRuleAssertThat =
        assertThatRule { SpacingBetweenDeclarationsWithAnnotationsRule() }

    @Test
    fun `Given consecutive KDoc comments before annotated declaration should not add blank line`() {
        val code =
            """
            public class JsonReader {
                public var lenient: Boolean = false

                /**
                 * Hey
                 */
                /** Sup */
                @get:Synchronized
                public var failOnUnknown: Boolean = false
            }
            """.trimIndent()
        // Should not report any violations since consecutive comments are already a violation
        // that will be caught by the no-consecutive-comments rule
        spacingBetweenDeclarationsWithAnnotationsRuleAssertThat(code).hasNoLintViolations()
    }

    @Test
    fun `Given consecutive block comments before annotated declaration should not add blank line`() {
        val code =
            """
            public class JsonReader {
                public var lenient: Boolean = false

                /* First comment */
                /* Second comment */
                @get:Synchronized
                public var failOnUnknown: Boolean = false
            }
            """.trimIndent()
        spacingBetweenDeclarationsWithAnnotationsRuleAssertThat(code).hasNoLintViolations()
    }

    @Test
    fun `Given consecutive EOL comments before annotated declaration should not add blank line`() {
        val code =
            """
            public class JsonReader {
                public var lenient: Boolean = false

                // First comment
                // Second comment
                @get:Synchronized
                public var failOnUnknown: Boolean = false
            }
            """.trimIndent()
        spacingBetweenDeclarationsWithAnnotationsRuleAssertThat(code).hasNoLintViolations()
    }

    @Test
    fun `Given mixed consecutive comments before annotated declaration should not add blank line`() {
        val code =
            """
            public class JsonReader {
                public var lenient: Boolean = false

                /** KDoc comment */
                // EOL comment
                @get:Synchronized
                public var failOnUnknown: Boolean = false
            }
            """.trimIndent()
        spacingBetweenDeclarationsWithAnnotationsRuleAssertThat(code).hasNoLintViolations()
    }

    @Test
    fun `Given single KDoc comment before annotated declaration should still add blank line`() {
        val code =
            """
            public class JsonReader {
                public var lenient: Boolean = false
                /** Single KDoc */
                @get:Synchronized
                public var failOnUnknown: Boolean = false
            }
            """.trimIndent()
        val formattedCode =
            """
            public class JsonReader {
                public var lenient: Boolean = false

                /** Single KDoc */
                @get:Synchronized
                public var failOnUnknown: Boolean = false
            }
            """.trimIndent()
        spacingBetweenDeclarationsWithAnnotationsRuleAssertThat(code)
            .hasLintViolation(3, 5, "Declarations and declarations with annotations should have an empty space between.")
            .isFormattedAs(formattedCode)
    }

    @Test
    fun `Given single EOL comment before annotated declaration should still add blank line`() {
        val code =
            """
            public class JsonReader {
                public var lenient: Boolean = false
                // Single comment
                @get:Synchronized
                public var failOnUnknown: Boolean = false
            }
            """.trimIndent()
        val formattedCode =
            """
            public class JsonReader {
                public var lenient: Boolean = false

                // Single comment
                @get:Synchronized
                public var failOnUnknown: Boolean = false
            }
            """.trimIndent()
        spacingBetweenDeclarationsWithAnnotationsRuleAssertThat(code)
            .hasLintViolation(4, 5, "Declarations and declarations with annotations should have an empty space between.")
            .isFormattedAs(formattedCode)
    }

    @Test
    fun `Given three consecutive comments before annotated declaration should not add blank line`() {
        val code =
            """
            public class JsonReader {
                public var lenient: Boolean = false

                /** First */
                /** Second */
                /** Third */
                @get:Synchronized
                public var failOnUnknown: Boolean = false
            }
            """.trimIndent()
        spacingBetweenDeclarationsWithAnnotationsRuleAssertThat(code).hasNoLintViolations()
    }

    @Test
    fun `Given consecutive comments separated by blank line before annotated declaration should still add blank line`() {
        val code =
            """
            public class JsonReader {
                public var lenient: Boolean = false
                /** First */

                /** Second */
                @get:Synchronized
                public var failOnUnknown: Boolean = false
            }
            """.trimIndent()
        // The blank line between comments breaks the consecutive comments, so the rule should apply
        val formattedCode =
            """
            public class JsonReader {
                public var lenient: Boolean = false

                /** First */

                /** Second */
                @get:Synchronized
                public var failOnUnknown: Boolean = false
            }
            """.trimIndent()
        spacingBetweenDeclarationsWithAnnotationsRuleAssertThat(code)
            .hasLintViolation(6, 5, "Declarations and declarations with annotations should have an empty space between.")
            .isFormattedAs(formattedCode)
    }
}
