     * Gets the previous element but ignores white whitespaces (excluding blank lines) and comments. Also checks
     * if there are consecutive comments (multiple comments separated only by single-newline whitespace) in the
     * traversed sequence. Returns a pair of (element, hasConsecutiveComments).
     * 
     * Note the difference with method [PsiElement.getPrevSiblingIgnoringWhitespaceAndComments] which excludes blank lines as well.
     */
    private fun PsiElement.getPrevLeafAndCheckConsecutiveComments(): Pair<PsiElement?, Boolean> {
        var prevLeaf: PsiElement? = this.prevLeaf()
        val iterator = prevLeafs.iterator()
        var commentCount = 0

        while (iterator.hasNext()) {
            val psiElement = iterator.next()
            val isComment = psiElement is PsiComment || 
                            psiElement.node.elementType == KDOC || 
