import com.pinterest.ktlint.test.KtLintAssertThat.Companion.assertThatRule
import org.junit.jupiter.api.Test

/**
 * Test for the fix of the issue where consecutive KDoc comments before an annotated declaration
 * cause the spacing-between-declarations-with-annotations rule to add an extra blank line,
 * which then triggers the no-consecutive-blank-lines rule.
 *
 * See: https://github.com/pinterest/ktlint/issues/...
 */
class SpacingBetweenDeclarationsWithAnnotationsRuleConsecutiveKDocTest {
    private val spacingBetweenDeclarationsWithAnnotationsRuleAssertThat =
        assertThatRule { SpacingBetweenDeclarationsWithAnnotationsRule() }

    @Test
    fun `Issue - consecutive KDoc comments before annotated declaration should not trigger extra blank line`() {
        // This is the exact code from the GitHub issue (simplified)
        val code =
            """
            public class JsonReader {
              public var lenient: Boolean = false

              /**
               * Hey
               */
              /** Sup */
              @get:Synchronized
              public var failOnUnknown: Boolean = false
            }
            """.trimIndent()

        // The rule should NOT trigger because there are consecutive KDoc comments
        // (which is already a violation that will be caught by no-consecutive-comments rule)
        // Adding a blank line would create consecutive blank lines
        spacingBetweenDeclarationsWithAnnotationsRuleAssertThat(code).hasNoLintViolations()
    }
}
